import net.minecraft.server.MinecraftServer;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.server.network.CommonListenerCookie;
import net.minecraft.server.network.ServerGamePacketListenerImpl;

public class FakeServerGamePacketListenerImpl extends ServerGamePacketListenerImpl {

    public FakeServerGamePacketListenerImpl(
            MinecraftServer server,
            Connection connection,
            ServerPlayer player,
            CommonListenerCookie cookie
    ) {
        super(server, connection, player, cookie);
    }

    @Override
    public void send(Packet<?> packet) {
        handlePacket(packet);
    }

    @Override
    public void send(Packet<?> packet, PacketSendListener listener) {
        handlePacket(packet);
    }

    @Override
    public void send(Packet<?> packet, PacketSendListener listener, boolean flush) {
        handlePacket(packet);
    }

    private void handlePacket(Packet<?> packet) {
        if (packet instanceof ClientboundRespawnPacket respawn) {
            handleRespawn(respawn);
        } else if (packet instanceof ClientboundSetEntityMotionPacket motion) {
            handleMotion(motion);
        }
    }

    private void handleRespawn(ClientboundRespawnPacket packet) {
        this.player.hasChangedDimension();
    }

    private void handleMotion(ClientboundSetEntityMotionPacket packet) {
        if (packet.getId() == this.player.getId() && this.player.hurtMarked) {
            this.player.hurtMarked = true;
            this.player.lerpMotion(packet.getMovement());
        }
    }

    @Override
    public void onDisconnect(net.minecraft.network.chat.Component reason) {
    }

    @Override
    public void disconnect(net.minecraft.network.chat.Component reason) {
    }

    @Override
    public void tick() {
        try {
            super.tick();
        } catch (Exception ignored) {
        }
    }
}

