package com.pvpbot.combat;

import com.pvpbot.bot.BotSettings;
import com.pvpbot.bot.CustomBot;
import net.minecraft.world.entity.LivingEntity;
import net.minecraft.world.entity.player.Player;
import net.minecraft.world.phys.AABB;
import net.minecraft.server.level.ServerLevel;
import org.jetbrains.annotations.Nullable;

public class CombatTargetSelector {

    @Nullable
    public static LivingEntity findTarget(ServerLevel level, CustomBot bot, BotSettings settings) {
        double viewDist = settings.getViewDistance();
        AABB searchBox = bot.getBoundingBox().inflate(viewDist);

        List<LivingEntity> candidates = level.getEntitiesOfClass(
            LivingEntity.class, 
            searchBox,
            entity -> isValidTarget(bot, entity, settings)
        );

        // Choose closest
        LivingEntity closest = null;
        double closestDist = Double.MAX_VALUE;
        for (LivingEntity candidate : candidates) {
            double dist = bot.distanceToSqr(candidate);
            if (dist < closestDist) {
                closestDist = dist;
                closest = candidate;
            }
        }
        return closest;
    }
}
```

