package com.pvpbot.bot;

import com.mojang.authlib.GameProfile;
import com.pvpbot.combat.MaceComboController;
import com.pvpbot.navigation.ArrowPrediction;
import com.pvpbot.navigation.BotMovementController;
import com.pvpbot.network.FakeConnection;
import com.pvpbot.network.FakeServerGamePacketListenerImpl;
import net.minecraft.core.BlockPos;
import net.minecraft.core.component.DataComponents;
import net.minecraft.network.protocol.game.ClientboundAddEntityPacket;
import net.minecraft.network.protocol.game.ClientboundPlayerInfoRemovePacket;
import net.minecraft.network.protocol.game.ClientboundPlayerInfoUpdatePacket;
import net.minecraft.network.protocol.game.ClientboundRemoveEntitiesPacket;
import net.minecraft.server.MinecraftServer;
import net.minecraft.server.level.ClientInformation;
import net.minecraft.server.level.ServerLevel;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.server.network.CommonListenerCookie;
import net.minecraft.world.InteractionHand;
import net.minecraft.world.damagesource.DamageSource;
import net.minecraft.world.entity.Entity;
import net.minecraft.world.entity.LivingEntity;
import net.minecraft.world.item.AxeItem;
import net.minecraft.world.item.CrossbowItem;
import net.minecraft.world.item.Item;
import net.minecraft.world.item.ItemStack;
import net.minecraft.world.item.Items;
import net.minecraft.world.item.enchantment.ItemEnchantments;
import net.minecraft.world.phys.Vec3;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.craftbukkit.CraftServer;
import org.bukkit.craftbukkit.CraftWorld;
import org.jetbrains.annotations.NotNull;
import org.jetbrains.annotations.Nullable;

import java.util.List;
import java.util.UUID;

public class CustomBot extends ServerPlayer {

    private static final Item[] SWORDS = {
            Items.NETHERITE_SWORD, Items.DIAMOND_SWORD, Items.IRON_SWORD,
            Items.STONE_SWORD, Items.GOLDEN_SWORD, Items.WOODEN_SWORD
    };

    private final UUID ownerUUID;
    private final String botName;
    private final FakeConnection fakeConnection;
    private final FakeServerGamePacketListenerImpl fakeListener;
    private final MinecraftServer serverInstance;
    private final BotSettings botSettings;
    private final BotMovementController movementController;
    private final MaceComboController maceComboController;

    private int attackCooldownTicks;
    private boolean awaitingCritJump;
    private int weaponCheckCooldown;

    public CustomBot(
            @NotNull MinecraftServer server,
            @NotNull ServerLevel level,
            @NotNull GameProfile profile,
            @NotNull ClientInformation clientInfo,
            @NotNull UUID ownerUUID,
            @NotNull String botName
    ) {
        super(server, level, profile, clientInfo);
        this.ownerUUID = ownerUUID;
        this.botName = botName;
        this.serverInstance = server;
        this.botSettings = new BotSettings();
        this.fakeConnection = new FakeConnection();
        this.movementController = new BotMovementController(this, botSettings);
        this.maceComboController = new MaceComboController(this, botSettings);

        CommonListenerCookie cookie = CommonListenerCookie.createInitial(profile, false);
        this.fakeListener = new FakeServerGamePacketListenerImpl(
                server, fakeConnection, this, cookie
        );
        this.connection = fakeListener;
    }

    @NotNull
    public static CustomBot spawn(
            @NotNull Location location,
            @Nullable String name,
            @NotNull UUID ownerUUID
    ) {
        MinecraftServer server = ((CraftServer) Bukkit.getServer()).getServer();
        ServerLevel level = ((CraftWorld) location.getWorld()).getHandle();

        String botName = (name != null && !name.isEmpty()) ? name : generateRandomName();
        UUID botUUID = UUID.randomUUID();
        GameProfile profile = new GameProfile(botUUID, botName);

        CustomBot bot = new CustomBot(server, level, profile, ClientInformation.createDefault(), ownerUUID, botName);

        bot.setPos(location.getX(), location.getY(), location.getZ());
        bot.setYRot(location.getYaw());
        bot.setXRot(location.getPitch());

        CommonListenerCookie cookie = CommonListenerCookie.createInitial(profile, false);
        server.getPlayerList().placeNewPlayer(bot.fakeConnection, bot, cookie);

        bot.connection = bot.fakeListener;

        return bot;
    }

    public void broadcastSpawnPackets() {
        ClientboundPlayerInfoUpdatePacket infoPacket = new ClientboundPlayerInfoUpdatePacket(
                ClientboundPlayerInfoUpdatePacket.Action.ADD_PLAYER, this
        );

        Vec3 pos = new Vec3(this.getX(), this.getY(), this.getZ());
        ClientboundAddEntityPacket spawnPacket = new ClientboundAddEntityPacket(
                this.getId(),
                this.getUUID(),
                pos.x(),
                pos.y(),
                pos.z(),
                this.getYRot(),
                this.getXRot(),
                this.getType(),
                0,
                Vec3.ZERO,
                0.0
        );

        for (ServerPlayer onlinePlayer : serverInstance.getPlayerList().getPlayers()) {
            if (onlinePlayer.equals(this)) continue;
            onlinePlayer.connection.send(infoPacket);
            onlinePlayer.connection.send(spawnPacket);
        }
    }

    public void broadcastRemovePackets() {
        ClientboundPlayerInfoRemovePacket removeInfoPacket =
                new ClientboundPlayerInfoRemovePacket(List.of(this.getUUID()));
        ClientboundRemoveEntitiesPacket removeEntityPacket =
                new ClientboundRemoveEntitiesPacket(this.getId());

        for (ServerPlayer onlinePlayer : serverInstance.getPlayerList().getPlayers()) {
            if (onlinePlayer.equals(this)) continue;
            onlinePlayer.connection.send(removeInfoPacket);
            onlinePlayer.connection.send(removeEntityPacket);
        }
    }

    @Override
    public void tick() {
        try {
            super.tick();
            if (attackCooldownTicks > 0) attackCooldownTicks--;
            if (weaponCheckCooldown > 0) weaponCheckCooldown--;
            if (isUsingItem()) {
                useItemRemaining--;
            }
            movementController.tick();
            maceComboController.tick(movementController.getCombatTarget());
            onBotTick();
        } catch (Exception ignored) {
        }
    }

    @Override
    public void aiStep() {
    }

    protected void onBotTick() {
    }

    public void removeFromWorld() {
        movementController.stop();
        broadcastRemovePackets();
        serverInstance.getPlayerList().remove(this);
        stopRiding();
        remove(Entity.RemovalReason.KILLED);
    }

    public void setCombatTarget(@Nullable LivingEntity target) {
        movementController.setCombatTarget(target);
    }

    public void setThreatEntity(@Nullable Entity entity) {
        movementController.setThreatEntity(entity);
    }

    public void moveTo(@NotNull BlockPos target) {
        movementController.moveTo(target);
    }

    public void stopMovement() {
        movementController.stop();
    }

    // --- Melee Combat ---

    public boolean canAttack() {
        return attackCooldownTicks <= 0;
    }

    public void resetAttackCooldown() {
        attackCooldownTicks = botSettings.getAttackCooldown();
    }

    public boolean isAwaitingCritJump() {
        return awaitingCritJump;
    }

    public void setAwaitingCritJump(boolean awaiting) {
        this.awaitingCritJump = awaiting;
    }

    public void performMeleeAttack(@NotNull LivingEntity target) {
        equipBestWeapon();
        attack(target);
    }

    public void equipBestWeapon() {
        if (weaponCheckCooldown > 0) return;
        weaponCheckCooldown = 10;

        boolean forceAxe = targetIsBlocking();
        boolean preferSword = botSettings.isPreferSword() && !forceAxe;

        int bestSlot = -1;
        int bestScore = -1;

        for (int i = 0; i < getInventory().getContainerSize(); i++) {
            ItemStack stack = getInventory().getItem(i);
            if (stack.isEmpty()) continue;
            int score = scoreWeapon(stack, preferSword);
            if (score > bestScore) {
                bestScore = score;
                bestSlot = i;
            }
        }

        if (bestSlot >= 0) {
            int hotbarSlot = bestSlot;
            if (bestSlot >= 9) {
                int currentSelected = getInventory().getSelectedSlot();
                ItemStack currentItem = getInventory().getItem(currentSelected);
                getInventory().setItem(bestSlot, currentItem);
                getInventory().setItem(currentSelected, getInventory().getItem(bestSlot));
            }
            getInventory().setSelectedSlot(hotbarSlot);
        }
    }

    private int scoreWeapon(ItemStack stack, boolean preferSword) {
        Item item = stack.getItem();
        boolean isSword = isSword(item);
        boolean isAxe = item instanceof AxeItem;

        if (!isSword && !isAxe) return -1;

        int tier = getTier(item);
        int enchantScore = getEnchantBonus(stack);
        int typeBonus = preferSword ? (isSword ? 3 : 1) : (isAxe ? 3 : 1);

        return tier * 10 + enchantScore + typeBonus;
    }

    private int getTier(Item item) {
        if (item == Items.NETHERITE_SWORD || item == Items.NETHERITE_AXE) return 5;
        if (item == Items.DIAMOND_SWORD || item == Items.DIAMOND_AXE) return 4;
        if (item == Items.IRON_SWORD || item == Items.IRON_AXE) return 3;
        if (item == Items.STONE_SWORD || item == Items.STONE_AXE) return 2;
        if (item == Items.GOLDEN_SWORD || item == Items.GOLDEN_AXE) return 1;
        if (item == Items.WOODEN_SWORD || item == Items.WOODEN_AXE) return 1;
        if (item == Items.COPPER_SWORD || item == Items.COPPER_AXE) return 2;
        return 0;
    }

    private int getEnchantBonus(ItemStack stack) {
        ItemEnchantments enchants = stack.get(DataComponents.ENCHANTMENTS);
        if (enchants == null) return 0;
        int bonus = 0;
        for (var entry : enchants.entrySet()) {
            bonus += entry.getIntValue();
        }
        return bonus;
    }

    private boolean isSword(Item item) {
        for (Item sword : SWORDS) {
            if (item == sword) return true;
        }
        return false;
    }

    private boolean targetIsBlocking() {
        LivingEntity target = movementController.getCombatTarget();
        return target != null && target.isBlocking();
    }

    // --- Shield ---

    public void equipShield() {
        ItemStack offhand = getOffhandItem();
        if (offhand.is(Items.SHIELD)) return;

        for (int i = 0; i < getInventory().getContainerSize(); i++) {
            ItemStack stack = getInventory().getItem(i);
            if (stack.is(Items.SHIELD)) {
                getInventory().setItem(i, offhand);
                getInventory().setItem(40, stack);
                break;
            }
        }
    }

    public boolean hasShieldInInventory() {
        for (int i = 0; i < getInventory().getContainerSize(); i++) {
            if (getInventory().getItem(i).is(Items.SHIELD)) return true;
        }
        return false;
    }

    public void raiseShield() {
        if (!isUsingItem()) {
            startUsingItem(InteractionHand.OFF_HAND);
        }
    }

    public void lowerShield() {
        if (isUsingItem()) {
            stopUsingItem();
        }
    }

    // --- Ranged Weapons ---

    public void startBowDraw() {
        if (!isUsingItem()) {
            startUsingItem(InteractionHand.MAIN_HAND);
        }
    }

    public void releaseBow() {
        if (isUsingItem()) {
            releaseUsingItem();
        }
    }

    public boolean hasBowOrCrossbowInInventory() {
        for (int i = 0; i < getInventory().getContainerSize(); i++) {
            ItemStack stack = getInventory().getItem(i);
            if (stack.is(Items.BOW) || stack.is(Items.CROSSBOW)) return true;
        }
        return false;
    }

    public void equipRangedWeapon() {
        int bowSlot = -1;
        int crossbowSlot = -1;
        for (int i = 0; i < getInventory().getContainerSize(); i++) {
            ItemStack stack = getInventory().getItem(i);
            if (stack.is(Items.BOW) && bowSlot < 0) bowSlot = i;
            if (stack.is(Items.CROSSBOW) && crossbowSlot < 0) crossbowSlot = i;
        }
        int slot = bowSlot >= 0 ? bowSlot : crossbowSlot;
        if (slot < 0) return;

        int currentSelected = getInventory().getSelectedSlot();
        int targetSlot = slot;
        if (slot >= 9) {
            ItemStack currentItem = getInventory().getItem(currentSelected);
            getInventory().setItem(slot, currentItem);
            getInventory().setItem(currentSelected, getInventory().getItem(slot));
            targetSlot = currentSelected;
        }
        getInventory().setSelectedSlot(targetSlot);
    }

    public boolean isHoldingRangedWeapon() {
        ItemStack main = getMainHandItem();
        return main.is(Items.BOW) || main.is(Items.CROSSBOW);
    }

    public boolean isCrossbowCharged() {
        ItemStack stack = getMainHandItem();
        return stack.is(Items.CROSSBOW) && CrossbowItem.isCharged(stack);
    }

    public void fireChargedCrossbow() {
        ItemStack crossbow = getMainHandItem();
        if (crossbow.is(Items.CROSSBOW) && CrossbowItem.isCharged(crossbow)) {
            crossbow.use(level(), this, InteractionHand.MAIN_HAND);
        }
    }

    // --- Wind Charge ---

    public void useWindCharge() {
        int slot = findItemSlot(Items.WIND_CHARGE);
        if (slot < 0) return;

        int currentSelected = getInventory().getSelectedSlot();
        equipFromSlot(slot);

        ItemStack windCharge = getMainHandItem();
        if (windCharge.is(Items.WIND_CHARGE)) {
            windCharge.use(level(), this, InteractionHand.MAIN_HAND);
        }

        if (slot >= 9) {
            ItemStack currentItem = getInventory().getItem(currentSelected);
            getInventory().setItem(slot, currentItem);
            getInventory().setItem(currentSelected, getInventory().getItem(slot));
        }
        getInventory().setSelectedSlot(currentSelected);
    }

    // --- Inventory Helpers ---

    public boolean hasItem(@NotNull Item item) {
        for (int i = 0; i < getInventory().getContainerSize(); i++) {
            if (getInventory().getItem(i).is(item)) return true;
        }
        return false;
    }

    public int findItemSlot(@NotNull Item item) {
        for (int i = 0; i < getInventory().getContainerSize(); i++) {
            if (getInventory().getItem(i).is(item)) return i;
        }
        return -1;
    }

    public void equipFromSlot(int slot) {
        if (slot < 0) return;
        int currentSelected = getInventory().getSelectedSlot();
        if (slot >= 9) {
            ItemStack currentItem = getInventory().getItem(currentSelected);
            getInventory().setItem(slot, currentItem);
            getInventory().setItem(currentSelected, getInventory().getItem(slot));
        }
        getInventory().setSelectedSlot(slot >= 9 ? currentSelected : slot);
    }

    // --- Damage ---

    @Override
    public boolean hurtServer(ServerLevel level, DamageSource source, float amount) {
        boolean result = super.hurtServer(level, source, amount);
        if (result && botSettings.isRevenge()) {
            Entity attacker = source.getEntity();
            if (attacker instanceof LivingEntity living && !living.equals(this)) {
                movementController.setCombatTarget(living);
            }
        }
        return result;
    }

    // --- Getters ---

    @NotNull
    public String getBotName() {
        return botName;
    }

    @NotNull
    public UUID getOwnerUUID() {
        return ownerUUID;
    }

    @NotNull
    public BotSettings getSettings() {
        return botSettings;
    }

    @NotNull
    public BotMovementController getMovementController() {
        return movementController;
    }

    @NotNull
    public MaceComboController getMaceComboController() {
        return maceComboController;
    }

    @NotNull
    private static String generateRandomName() {
        String[] prefixes = {"Fighter", "Bot", "Dummy", "Target", "Sparring"};
        String prefix = prefixes[(int) (Math.random() * prefixes.length)];
        int suffix = 1000 + (int) (Math.random() * 9000);
        return prefix + suffix;
    }
}

package com.pvpbot.navigation;

import com.pvpbot.bot.BotSettings;
import com.pvpbot.bot.CustomBot;
import com.pvpbot.combat.CombatTargetSelector;
import net.minecraft.core.BlockPos;
import net.minecraft.server.level.ServerLevel;
import net.minecraft.world.entity.Entity;
import net.minecraft.world.entity.LivingEntity;
import net.minecraft.world.item.AxeItem;
import net.minecraft.world.item.Items;
import net.minecraft.world.level.Level;
import net.minecraft.world.phys.Vec3;
import org.jetbrains.annotations.NotNull;
import org.jetbrains.annotations.Nullable;

import java.util.List;

public class BotMovementController {

    private static final double JUMP_VELOCITY = 0.42;
    private static final double BHOP_MOMENTUM = 1.2;
    private static final double GROUND_FRICTION = 0.6;

    private final CustomBot bot;
    private final BotSettings settings;

    private List<BlockPos> currentPath;
    private int pathIndex;
    private int pathRecalculateCooldown;
    private BlockPos pathTarget;
    private int pathTicks;

    private double targetYaw;
    private double targetPitch;
    private float currentYaw;
    private float currentPitch;

    private boolean wasOnGround;

    private int wanderCooldown;
    private BlockPos wanderTarget;

    private int strafeTimer;
    private boolean strafeLeft;

    @Nullable private LivingEntity combatTarget;
    @Nullable private Entity threatEntity;

    private int targetSearchCooldown;

    private int shieldState;
    private int shieldTimer;
    private int attackCooldownTimer;
    private boolean awaitingCritJump;

    private int rangedDrawTimer;
    private int rangedCooldownTimer;
    private int rangedStrafeTimer;
    private boolean rangedStrafeLeft;
    private int rangedState;

    public BotMovementController(@NotNull CustomBot bot, @NotNull BotSettings settings) {
        this.bot = bot;
        this.settings = settings;
        this.currentYaw = bot.getYRot();
        this.currentPitch = bot.getXRot();
        this.wasOnGround = bot.onGround();
    }

    public void setCombatTarget(@Nullable LivingEntity target) {
        this.combatTarget = target;
        if (target != null) {
            this.pathTarget = target.blockPosition();
            this.currentPath = null;
        }
    }

    public void setThreatEntity(@Nullable Entity entity) {
        this.threatEntity = entity;
    }

    @Nullable
    public LivingEntity getCombatTarget() {
        return combatTarget;
    }

    public void moveTo(@NotNull BlockPos target) {
        if (!target.equals(this.pathTarget)) {
            this.pathTarget = target;
            this.currentPath = null;
            this.pathIndex = 0;
        }
    }

    public void stop() {
        this.currentPath = null;
        this.pathTarget = null;
        this.pathIndex = 0;
        this.combatTarget = null;
        this.threatEntity = null;
        this.wanderTarget = null;
        this.shieldState = 0;
        this.shieldTimer = 0;
        this.rangedState = 0;
        this.rangedDrawTimer = 0;
        bot.lowerShield();
        if (bot.isUsingItem()) bot.stopUsingItem();
        bot.setDeltaMovement(Vec3.ZERO);
    }

    public boolean hasPath() {
        return currentPath != null && pathIndex < currentPath.size();
    }

    public boolean isMoving() {
        Vec3 vel = bot.getDeltaMovement();
        return vel.x * vel.x + vel.z * vel.z > 0.001;
    }

    public void tick() {
        Level level = bot.level();
        if (!(level instanceof ServerLevel serverLevel)) return;

        if (pathRecalculateCooldown > 0) pathRecalculateCooldown--;
        if (wanderCooldown > 0) wanderCooldown--;
        if (attackCooldownTimer > 0) attackCooldownTimer--;
        if (targetSearchCooldown > 0) targetSearchCooldown--;

        boolean onGround = bot.onGround();

        handleTargetSelection(serverLevel);
        verifyCombatTarget();

        boolean maceActive = bot.getMaceComboController().isActive();

        if (!maceActive) {
            if (combatTarget != null) {
                handleCombatMovement();
            } else if (settings.isRetreat() && shouldRetreat()) {
                handleRetreatMovement();
            } else if (settings.isIdle() && pathTarget == null && !hasPath()) {
                handleWanderMovement(level);
            } else if (pathTarget != null) {
                followPath(level);
            }

            if (hasPath()) {
                moveAlongPath(level);
            }
        }

        if (combatTarget != null && !maceActive) {
            updateRotation(level);
        } else if (hasPath() && !maceActive) {
            updateRotation(level);
        }

        if (combatTarget != null && settings.isCombat() && !maceActive) {
            handleCombatDecision();
        }

        handleShield();

        applyFriction(onGround);
        if (!maceActive) {
            handleCritJump(onGround);
        }

        wasOnGround = onGround;
    }

    private void handleCombatDecision() {
        if (combatTarget == null) return;
        double distSq = bot.distanceToSqr(combatTarget);
        double meleeRangeSq = settings.getMeleeRange() * settings.getMeleeRange();

        boolean useRanged = settings.isRanged()
                && bot.hasBowOrCrossbowInInventory()
                && distSq >= settings.getRangedMinRange() * settings.getRangedMinRange()
                && distSq <= settings.getRangedMaxRange() * settings.getRangedMaxRange();

        if (useRanged) {
            handleRangedCombat(distSq);
        } else if (distSq <= meleeRangeSq) {
            handleMeleeAttack();
        }
    }

    private void handleTargetSelection(ServerLevel serverLevel) {
        if (settings.isAutoTarget() && combatTarget == null && targetSearchCooldown <= 0) {
            LivingEntity found = CombatTargetSelector.findTarget(serverLevel, bot, settings);
            if (found != null) {
                setCombatTarget(found);
            }
            targetSearchCooldown = 20;
        }
    }

    private void verifyCombatTarget() {
        if (combatTarget != null && (!combatTarget.isAlive() || combatTarget.isRemoved())) {
            combatTarget = null;
        }
    }

    private boolean shouldRetreat() {
        if (combatTarget != null) return false;
        float health = bot.getHealth();
        float maxHealth = bot.getMaxHealth();
        return maxHealth > 0 && (health / maxHealth) < settings.getRetreatHealth();
    }

    private void handleCombatMovement() {
        if (combatTarget == null) return;

        BlockPos targetPos = combatTarget.blockPosition();
        BlockPos botPos = bot.blockPosition();
        double distSq = botPos.distSqr(targetPos);
        double meleeRangeSq = settings.getMeleeRange() * settings.getMeleeRange();
        boolean isClose = distSq < meleeRangeSq;

        boolean rangedMode = settings.isRanged()
                && bot.hasBowOrCrossbowInInventory()
                && distSq >= settings.getRangedMinRange() * settings.getRangedMinRange()
                && distSq <= settings.getRangedMaxRange() * settings.getRangedMaxRange();

        if (pathRecalculateCooldown <= 0 || currentPath == null) {
            BlockPos offset;
            if (rangedMode) {
                offset = calcRangedOffset(botPos, targetPos, distSq);
            } else if (settings.isCombatStrafe() && distSq < 64.0) {
                strafeTimer++;
                if (strafeTimer > settings.getCombatStrafeInterval()) {
                    strafeLeft = !strafeLeft;
                    strafeTimer = 0;
                }
                int dx = targetPos.getX() - botPos.getX();
                int dz = targetPos.getZ() - botPos.getZ();
                double angle = Math.atan2(dz, dx);
                angle += strafeLeft ? Math.PI / 2 : -Math.PI / 2;
                int strafeX = (int) Math.round(Math.cos(angle) * 3);
                int strafeZ = (int) Math.round(Math.sin(angle) * 3);
                offset = new BlockPos(targetPos.getX() + strafeX, targetPos.getY(), targetPos.getZ() + strafeZ);
            } else {
                offset = targetPos;
            }
            recalculatePath(offset);
            pathRecalculateCooldown = 10;
        }

        if (rangedMode && settings.isArrowPrediction()) {
            double dist = Math.sqrt(distSq);
            Vec3 predicted = ArrowPrediction.predictPosition(combatTarget, dist);
            setLookTarget(predicted.x, predicted.y, predicted.z);
        } else {
            Vec3 lookTarget = combatTarget.position().add(0, combatTarget.getEyeHeight() * 0.7, 0);
            setLookTarget(lookTarget.x, lookTarget.y, lookTarget.z);
        }
    }

    private BlockPos calcRangedOffset(BlockPos botPos, BlockPos targetPos, double distSq) {
        double dist = Math.sqrt(distSq);
        int dx = botPos.getX() - targetPos.getX();
        int dz = botPos.getZ() - targetPos.getZ();

        if (settings.isRangedRetreat() && dist < settings.getRangedMinRange()) {
            if (dx == 0 && dz == 0) { dx = 1; dz = 0; }
            double len = Math.sqrt(dx * dx + dz * dz);
            int rx = botPos.getX() + (int) Math.round((dx / len) * 5);
            int rz = botPos.getZ() + (int) Math.round((dz / len) * 5);
            return new BlockPos(rx, botPos.getY(), rz);
        }

        if (settings.isRangedStrafe()) {
            rangedStrafeTimer++;
            if (rangedStrafeTimer > 20 + bot.getRandom().nextInt(20)) {
                rangedStrafeLeft = !rangedStrafeLeft;
                rangedStrafeTimer = 0;
            }
            double angle = Math.atan2(dz, dx);
            angle += rangedStrafeLeft ? Math.PI / 2 : -Math.PI / 2;
            int sx = targetPos.getX() + (int) Math.round(Math.cos(angle) * 4);
            int sz = targetPos.getZ() + (int) Math.round(Math.sin(angle) * 4);
            return new BlockPos(sx, botPos.getY(), sz);
        }

        return targetPos;
    }

    private void handleRangedCombat(double distSq) {
        double dist = Math.sqrt(distSq);

        if (!bot.isHoldingRangedWeapon()) {
            bot.equipRangedWeapon();
        }

        if (rangedCooldownTimer > 0) {
            rangedCooldownTimer--;
            return;
        }

        switch (rangedState) {
            case 0 -> {
                if (!bot.isUsingItem()) {
                    if (bot.isCrossbowCharged()) {
                        bot.fireChargedCrossbow();
                        rangedCooldownTimer = settings.getAttackCooldown() + settings.getBowDrawTicks();
                    } else {
                        bot.startBowDraw();
                        rangedState = 1;
                        rangedDrawTimer = 0;
                    }
                }
            }
            case 1 -> {
                rangedDrawTimer++;
                if (bot.isCrossbowCharged()) {
                    bot.stopUsingItem();
                    bot.fireChargedCrossbow();
                    rangedState = 0;
                    rangedCooldownTimer = settings.getAttackCooldown() + settings.getBowDrawTicks();
                } else if (rangedDrawTimer >= settings.getBowDrawTicks()) {
                    bot.releaseBow();
                    rangedState = 2;
                    rangedDrawTimer = 0;
                }
            }
            case 2 -> {
                rangedCooldownTimer = settings.getAttackCooldown();
                rangedState = 0;
            }
        }
    }

    private void handleRetreatMovement() {
        if (threatEntity == null || !threatEntity.isAlive()) {
            threatEntity = null;
            return;
        }

        BlockPos botPos = bot.blockPosition();
        BlockPos threatPos = threatEntity.blockPosition();
        int dx = botPos.getX() - threatPos.getX();
        int dz = botPos.getZ() - threatPos.getZ();
        if (dx == 0 && dz == 0) { dx = 1; dz = 0; }
        double len = Math.sqrt(dx * dx + dz * dz);
        int retreatX = botPos.getX() + (int) Math.round((dx / len) * 10);
        int retreatZ = botPos.getZ() + (int) Math.round((dz / len) * 10);

        BlockPos retreatPos = new BlockPos(retreatX, botPos.getY(), retreatZ);

        if (pathRecalculateCooldown <= 0 || currentPath == null) {
            recalculatePath(retreatPos);
            pathRecalculateCooldown = 15;
        }
    }

    private void handleWanderMovement(@NotNull Level level) {
        if (wanderCooldown > 0) return;

        if (wanderTarget != null && bot.blockPosition().distSqr(wanderTarget) < 2.0) {
            wanderTarget = null;
            wanderCooldown = 20 + bot.getRandom().nextInt(40);
            currentPath = null;
            return;
        }

        if (pathRecalculateCooldown <= 0 || currentPath == null) {
            BlockPos botPos = bot.blockPosition();
            for (int attempt = 0; attempt < 10; attempt++) {
                int rx = botPos.getX() + (bot.getRandom().nextInt(settings.getIdleRadius() * 2 + 1) - settings.getIdleRadius());
                int rz = botPos.getZ() + (bot.getRandom().nextInt(settings.getIdleRadius() * 2 + 1) - settings.getIdleRadius());
                int ry = botPos.getY();
                wanderTarget = new BlockPos(rx, ry, rz);
                break;
            }
            if (wanderTarget != null) {
                recalculatePath(wanderTarget);
                pathRecalculateCooldown = 20;
            }
        }
    }

    private void followPath(@NotNull Level level) {
        if (currentPath == null || pathTarget == null) return;

        pathTicks++;
        if (pathRecalculateCooldown <= 0 && pathTicks > 20) {
            BlockPos botPos = bot.blockPosition();
            if (botPos.distSqr(pathTarget) > 4.0) {
                recalculatePath(pathTarget);
            }
            pathTicks = 0;
            pathRecalculateCooldown = 20;
        }

        if (pathIndex >= currentPath.size()) {
            currentPath = null;
        }
    }

    private void moveAlongPath(@NotNull Level level) {
        if (currentPath == null || pathIndex >= currentPath.size()) return;

        BlockPos targetNode = currentPath.get(pathIndex);
        Vec3 botPos = bot.position();

        double dx = targetNode.getX() + 0.5 - botPos.x;
        double dz = targetNode.getZ() + 0.5 - botPos.z;
        double distSqr = dx * dx + dz * dz;

        if (distSqr < 0.4) {
            pathIndex++;
            if (pathIndex >= currentPath.size()) {
                currentPath = null;
                return;
            }
            targetNode = currentPath.get(pathIndex);
            dx = targetNode.getX() + 0.5 - botPos.x;
            dz = targetNode.getZ() + 0.5 - botPos.z;
        }

        int targetY = targetNode.getY();
        int botY = bot.blockPosition().getY();
        boolean onGround = bot.onGround();

        if (targetY > botY && onGround) {
            bot.setDeltaMovement(bot.getDeltaMovement().x, JUMP_VELOCITY, bot.getDeltaMovement().z);
        } else if (settings.isBhop() && onGround && isMoving()) {
            bot.setDeltaMovement(bot.getDeltaMovement().x, JUMP_VELOCITY, bot.getDeltaMovement().z);
            Vec3 vel = bot.getDeltaMovement();
            bot.setDeltaMovement(vel.x * BHOP_MOMENTUM, vel.y, vel.z * BHOP_MOMENTUM);
        }

        double speed = settings.getMoveSpeed();
        double len = Math.sqrt(dx * dx + dz * dz);
        if (len > 0.01) {
            double velX = (dx / len) * speed;
            double velZ = (dz / len) * speed;
            Vec3 currentVel = bot.getDeltaMovement();
            if (onGround) {
                bot.setDeltaMovement(velX, currentVel.y, velZ);
            } else {
                bot.setDeltaMovement(
                        currentVel.x + (velX - currentVel.x) * 0.3,
                        currentVel.y,
                        currentVel.z + (velZ - currentVel.z) * 0.3
                );
            }
        }
    }

    private void handleMeleeAttack() {
        if (combatTarget == null) return;

        double distSq = bot.distanceToSqr(combatTarget);
        double range = settings.getMeleeRange();
        if (distSq > range * range) return;

        if (attackCooldownTimer > 0) return;

        if (settings.isCriticals() && bot.onGround()) {
            bot.setDeltaMovement(bot.getDeltaMovement().x, JUMP_VELOCITY, bot.getDeltaMovement().z);
            awaitingCritJump = true;
            bot.setAwaitingCritJump(true);
            return;
        }

        if (settings.isCriticals() && awaitingCritJump) {
            if (!bot.onGround() && bot.getDeltaMovement().y < 0) {
                executeAttack();
                awaitingCritJump = false;
                bot.setAwaitingCritJump(false);
            }
            return;
        }

        executeAttack();
    }

    private void executeAttack() {
        if (combatTarget == null) return;

        boolean wasBlocking = combatTarget.isBlocking();
        boolean isHoldingAxe = bot.getMainHandItem().getItem() instanceof AxeItem;

        bot.performMeleeAttack(combatTarget);
        attackCooldownTimer = settings.getAttackCooldown();

        if (wasBlocking && isHoldingAxe && settings.isShieldBreak()) {
            double roll = bot.getRandom().nextDouble() * 100.0;
            if (roll < settings.getShieldBreakChance()) {
                if (combatTarget instanceof net.minecraft.world.entity.player.Player targetPlayer) {
                    targetPlayer.getCooldowns().addCooldown(new net.minecraft.world.item.ItemStack(Items.SHIELD), 100);
                }
            }
        }
    }

    private void handleCritJump(boolean onGround) {
        if (awaitingCritJump && onGround) {
            awaitingCritJump = false;
            bot.setAwaitingCritJump(false);
        }
    }

    private void handleShield() {
        if (!settings.isAutoShield()) {
            if (shieldState != 0) {
                shieldState = 0;
                shieldTimer = 0;
                bot.lowerShield();
            }
            return;
        }

        if (!bot.getOffhandItem().is(Items.SHIELD) && bot.hasShieldInInventory()) {
            bot.equipShield();
        }

        boolean shouldRaise = shouldRaiseShield();

        switch (shieldState) {
            case 0 -> {
                if (shouldRaise) {
                    shieldState = 1;
                    shieldTimer = 0;
                }
            }
            case 1 -> {
                shieldTimer++;
                if (!shouldRaise) {
                    shieldState = 0;
                    shieldTimer = 0;
                    break;
                }
                if (shieldTimer >= settings.getShieldRaiseTicks()) {
                    bot.raiseShield();
                    shieldState = 2;
                    shieldTimer = 0;
                }
            }
            case 2 -> {
                shieldTimer++;
                if (!shouldRaise) {
                    bot.lowerShield();
                    shieldState = 3;
                    shieldTimer = 0;
                    break;
                }
                if (shieldTimer >= settings.getShieldHoldTicks()) {
                    bot.lowerShield();
                    shieldState = 3;
                    shieldTimer = 0;
                }
            }
            case 3 -> {
                shieldTimer++;
                if (shieldTimer >= 10) {
                    shieldState = 0;
                    shieldTimer = 0;
                }
            }
        }
    }

    private boolean shouldRaiseShield() {
        if (combatTarget == null) return false;

        if (combatTarget.isUsingItem()) {
            if (isTargetRanged()) {
                if (isTargetAimingAtBot()) {
                    return true;
                }
            }
        }

        if (settings.isShieldMace() && isTargetUsingMace()) {
            if (!combatTarget.onGround() && combatTarget.getDeltaMovement().y < 0
                    && combatTarget.position().y > bot.position().y + 2.0) {
                return true;
            }
        }

        return false;
    }

    private boolean isTargetRanged() {
        if (combatTarget == null) return false;
        var useItem = combatTarget.getUseItem();
        return useItem.is(Items.BOW) || useItem.is(Items.CROSSBOW);
    }

    private boolean isTargetAimingAtBot() {
        if (combatTarget == null) return false;
        Vec3 lookVec = combatTarget.getLookAngle();
        Vec3 toBot = bot.position().subtract(combatTarget.position()).normalize();
        double dot = lookVec.dot(toBot);
        return dot > 0.5;
    }

    private boolean isTargetUsingMace() {
        if (combatTarget == null) return false;
        return combatTarget.getMainHandItem().is(Items.MACE);
    }

    private void updateRotation(@NotNull Level level) {
        if (combatTarget != null) {
            Vec3 target = combatTarget.position().add(0, combatTarget.getEyeHeight() * 0.7, 0);
            smoothRotateTowards(target.x, target.y, target.z);
        } else if (hasPath() && pathIndex < currentPath.size()) {
            BlockPos node = currentPath.get(pathIndex);
            smoothRotateTowards(node.getX() + 0.5, node.getY() + 0.5, node.getZ() + 0.5);
        }
    }

    private void setLookTarget(double x, double y, double z) {
        Vec3 botPos = bot.position();
        Vec3 eyePos = botPos.add(0, bot.getEyeHeight(), 0);
        double dx = x - eyePos.x;
        double dy = y - eyePos.y;
        double dz = z - eyePos.z;
        double horizDist = Math.sqrt(dx * dx + dz * dz);

        this.targetYaw = Math.toDegrees(Math.atan2(-dx, -dz));
        this.targetPitch = -Math.toDegrees(Math.atan2(dy, Math.max(horizDist, 0.001)));
    }

    private void smoothRotateTowards(double x, double y, double z) {
        setLookTarget(x, y, z);
        float aimSpeed = (float) settings.getAimSpeed();

        currentYaw = lerpAngle(currentYaw, (float) targetYaw, aimSpeed);
        currentPitch = lerpAngle(currentPitch, (float) targetPitch, aimSpeed * 0.8f);

        bot.setYRot(currentYaw);
        bot.setXRot(currentPitch);

        if (bot.getBukkitEntity() != null) {
            bot.getBukkitEntity().setRotation(currentYaw, currentPitch);
        }
    }

    private void applyFriction(boolean onGround) {
        if (onGround && !isMoving()) {
            Vec3 vel = bot.getDeltaMovement();
            bot.setDeltaMovement(vel.x * GROUND_FRICTION, vel.y, vel.z * GROUND_FRICTION);
        }
    }

    private void recalculatePath(@NotNull BlockPos target) {
        Level level = bot.level();
        if (level == null) return;
        BlockPos start = bot.blockPosition();
        List<BlockPos> path = AStarPathfinder.findPath(level, start, target);
        if (path != null && path.size() > 1) {
            this.currentPath = path;
            this.pathIndex = 1;
            this.pathTarget = target;
            this.pathTicks = 0;
        } else {
            this.currentPath = null;
        }
    }

    private static float lerpAngle(float from, float to, float speed) {
        float diff = to - from;
        while (diff < -180) diff += 360;
        while (diff > 180) diff -= 360;
        return from + diff * Math.min(speed, 1.0f);
    }

    @Nullable
    public List<BlockPos> getCurrentPath() {
        return currentPath;
    }

    @Nullable
    public BlockPos getPathTarget() {
        return pathTarget;
    }
}

package com.pvpbot.command;

import com.pvpbot.bot.BotManager;
import com.pvpbot.bot.BotSettings;
import com.pvpbot.bot.CustomBot;
import org.bukkit.Location;
import org.bukkit.command.Command;
import org.bukkit.command.CommandSender;
import org.bukkit.command.TabExecutor;
import org.bukkit.entity.Player;
import org.jetbrains.annotations.NotNull;
import org.jetbrains.annotations.Nullable;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.stream.Collectors;
import java.util.stream.Stream;

public class PvPBotCommand implements TabExecutor {

    private static final List<String> SETTING_KEYS = List.of(
            "move-speed", "bhop", "idle", "idle-radius",
            "retreat", "retreat-health", "view-distance", "aim-speed",
            "combat", "auto-target", "target-players", "target-mobs", "target-bots",
            "revenge", "criticals", "attack-cooldown", "melee-range",
            "prefer-sword", "auto-shield", "shield-break", "shield-break-chance",
            "shield-hold-ticks", "shield-raise-ticks", "shield-mace",
            "ranged", "mace", "ranged-min-range", "ranged-optimal-range",
            "ranged-max-range", "bow-draw-ticks", "arrow-prediction",
            "ranged-strafe", "ranged-retreat"
    );

    private static final List<String> BOOLEAN_KEYS = List.of(
            "bhop", "idle", "retreat", "combat", "auto-target",
            "target-players", "target-mobs", "target-bots",
            "revenge", "criticals", "prefer-sword", "auto-shield",
            "shield-break", "shield-mace",
            "ranged", "mace", "arrow-prediction", "ranged-strafe", "ranged-retreat"
    );

    private final BotManager botManager;

    public PvPBotCommand(@NotNull BotManager botManager) {
        this.botManager = botManager;
    }

    @Override
    public boolean onCommand(
            @NotNull CommandSender sender,
            @NotNull Command command,
            @NotNull String label,
            @NotNull String[] args
    ) {
        if (args.length == 0) {
            sendUsage(sender);
            return true;
        }

        switch (args[0].toLowerCase()) {
            case "spawn" -> handleSpawn(sender, args);
            case "remove" -> handleRemove(sender, args);
            case "removeall" -> handleRemoveAll(sender);
            case "reload" -> handleReload(sender);
            case "list" -> handleList(sender);
            case "settings" -> handleSettings(sender, args);
            case "move" -> handleMove(sender, args);
            case "stop" -> handleStop(sender, args);
            default -> sendUsage(sender);
        }
        return true;
    }

    private void handleSpawn(@NotNull CommandSender sender, @NotNull String[] args) {
        if (!(sender instanceof Player player)) {
            sender.sendMessage("§cOnly players can spawn bots");
            return;
        }

        String name = args.length >= 2 ? args[1] : null;

        if (name != null && name.length() > 16) {
            sender.sendMessage("§cBot name must be 16 characters or less");
            return;
        }

        Location spawnLocation = player.getLocation();
        CustomBot bot = botManager.spawnBot(spawnLocation, name, player);

        if (bot != null) {
            sender.sendMessage("§aBot '" + bot.getBotName() + "' spawned at your location");
        }
    }

    private void handleRemove(@NotNull CommandSender sender, @NotNull String[] args) {
        if (args.length < 2) {
            sender.sendMessage("§cUsage: /pvpbot remove <name>");
            return;
        }

        String name = args[1];
        if (botManager.removeBot(name)) {
            sender.sendMessage("§aBot '" + name + "' removed");
        } else {
            sender.sendMessage("§cNo bot found with name '" + name + "'");
        }
    }

    private void handleRemoveAll(@NotNull CommandSender sender) {
        if (!sender.hasPermission("pvpbot.admin")) {
            sender.sendMessage("§cYou don't have permission to use this command");
            return;
        }

        int count = botManager.getBotCount();
        botManager.removeAll();
        sender.sendMessage("§aRemoved " + count + " bot(s)");
    }

    private void handleReload(@NotNull CommandSender sender) {
        if (!sender.hasPermission("pvpbot.admin")) {
            sender.sendMessage("§cYou don't have permission to use this command");
            return;
        }

        try {
            org.bukkit.plugin.java.JavaPlugin plugin =
                    (org.bukkit.plugin.java.JavaPlugin) org.bukkit.Bukkit.getPluginManager().getPlugin("PvPBot");
            if (plugin != null) {
                plugin.reloadConfig();
            }
            botManager.loadConfig();
            sender.sendMessage("§aConfiguration reloaded");
        } catch (Exception e) {
            sender.sendMessage("§cFailed to reload config: " + e.getMessage());
        }
    }

    private void handleList(@NotNull CommandSender sender) {
        List<CustomBot> allBots = new ArrayList<>(botManager.getAllBots());
        if (allBots.isEmpty()) {
            sender.sendMessage("§eNo bots active");
            return;
        }

        sender.sendMessage("§6Active bots (" + allBots.size() + "):");
        for (CustomBot bot : allBots) {
            sender.sendMessage("§7 - §f" + bot.getBotName() + " §7(UUID: " + bot.getUUID() + ")");
        }
    }

    private void handleSettings(@NotNull CommandSender sender, @NotNull String[] args) {
        if (args.length < 2) {
            sender.sendMessage("§cUsage: /pvpbot settings <botname> [<setting> <value>]");
            sender.sendMessage("§7Settings: " + String.join(", ", SETTING_KEYS));
            return;
        }

        String botName = args[1];
        CustomBot bot = botManager.getBot(botName);
        if (bot == null) {
            sender.sendMessage("§cNo bot found with name '" + botName + "'");
            return;
        }

        BotSettings s = bot.getSettings();

        if (args.length == 2) {
            sender.sendMessage("§6Settings for bot '" + bot.getBotName() + "':");
            sender.sendMessage("§7  move-speed: §f" + s.getMoveSpeed());
            sender.sendMessage("§7  bhop: §f" + s.isBhop());
            sender.sendMessage("§7  idle: §f" + s.isIdle());
            sender.sendMessage("§7  idle-radius: §f" + s.getIdleRadius());
            sender.sendMessage("§7  retreat: §f" + s.isRetreat());
            sender.sendMessage("§7  retreat-health: §f" + s.getRetreatHealth());
            sender.sendMessage("§7  view-distance: §f" + s.getViewDistance());
            sender.sendMessage("§7  aim-speed: §f" + s.getAimSpeed());
            sender.sendMessage("§7  combat: §f" + s.isCombat());
            sender.sendMessage("§7  auto-target: §f" + s.isAutoTarget());
            sender.sendMessage("§7  target-players: §f" + s.isTargetPlayers());
            sender.sendMessage("§7  target-mobs: §f" + s.isTargetMobs());
            sender.sendMessage("§7  target-bots: §f" + s.isTargetBots());
            sender.sendMessage("§7  revenge: §f" + s.isRevenge());
            sender.sendMessage("§7  criticals: §f" + s.isCriticals());
            sender.sendMessage("§7  attack-cooldown: §f" + s.getAttackCooldown());
            sender.sendMessage("§7  melee-range: §f" + s.getMeleeRange());
            sender.sendMessage("§7  prefer-sword: §f" + s.isPreferSword());
            sender.sendMessage("§7  auto-shield: §f" + s.isAutoShield());
            sender.sendMessage("§7  shield-break: §f" + s.isShieldBreak());
            sender.sendMessage("§7  shield-break-chance: §f" + s.getShieldBreakChance());
            sender.sendMessage("§7  shield-hold-ticks: §f" + s.getShieldHoldTicks());
            sender.sendMessage("§7  shield-raise-ticks: §f" + s.getShieldRaiseTicks());
            sender.sendMessage("§7  shield-mace: §f" + s.isShieldMace());
            sender.sendMessage("§7  ranged: §f" + s.isRanged());
            sender.sendMessage("§7  mace: §f" + s.isMace());
            sender.sendMessage("§7  ranged-min-range: §f" + s.getRangedMinRange());
            sender.sendMessage("§7  ranged-optimal-range: §f" + s.getRangedOptimalRange());
            sender.sendMessage("§7  ranged-max-range: §f" + s.getRangedMaxRange());
            sender.sendMessage("§7  bow-draw-ticks: §f" + s.getBowDrawTicks());
            sender.sendMessage("§7  arrow-prediction: §f" + s.isArrowPrediction());
            sender.sendMessage("§7  ranged-strafe: §f" + s.isRangedStrafe());
            sender.sendMessage("§7  ranged-retreat: §f" + s.isRangedRetreat());
            return;
        }

        if (args.length < 4) {
            sender.sendMessage("§cUsage: /pvpbot settings <botname> <setting> <value>");
            return;
        }

        String setting = args[2].toLowerCase();
        String value = args[3];

        switch (setting) {
            case "move-speed" -> setDouble(sender, value, s::setMoveSpeed, 0.1, 2.0);
            case "bhop" -> setBool(sender, value, s::setBhop);
            case "idle" -> setBool(sender, value, s::setIdle);
            case "idle-radius" -> setInt(sender, value, s::setIdleRadius, 3, 50);
            case "retreat" -> setBool(sender, value, s::setRetreat);
            case "retreat-health" -> setDouble(sender, value, s::setRetreatHealth, 0.0, 1.0);
            case "view-distance" -> setDouble(sender, value, s::setViewDistance, 5, 128);
            case "aim-speed" -> setDouble(sender, value, s::setAimSpeed, 0.01, 1.0);
            case "combat" -> setBool(sender, value, s::setCombat);
            case "auto-target" -> setBool(sender, value, s::setAutoTarget);
            case "target-players" -> setBool(sender, value, s::setTargetPlayers);
            case "target-mobs" -> setBool(sender, value, s::setTargetMobs);
            case "target-bots" -> setBool(sender, value, s::setTargetBots);
            case "revenge" -> setBool(sender, value, s::setRevenge);
            case "criticals" -> setBool(sender, value, s::setCriticals);
            case "attack-cooldown" -> setInt(sender, value, s::setAttackCooldown, 2, 60);
            case "melee-range" -> setDouble(sender, value, s::setMeleeRange, 2.0, 6.0);
            case "prefer-sword" -> setBool(sender, value, s::setPreferSword);
            case "auto-shield" -> setBool(sender, value, s::setAutoShield);
            case "shield-break" -> setBool(sender, value, s::setShieldBreak);
            case "shield-break-chance" -> setDouble(sender, value, s::setShieldBreakChance, 0, 100);
            case "shield-hold-ticks" -> setInt(sender, value, s::setShieldHoldTicks, 10, 200);
            case "shield-raise-ticks" -> setInt(sender, value, s::setShieldRaiseTicks, 0, 40);
            case "shield-mace" -> setBool(sender, value, s::setShieldMace);
            case "ranged" -> setBool(sender, value, s::setRanged);
            case "mace" -> setBool(sender, value, s::setMace);
            case "ranged-min-range" -> setDouble(sender, value, s::setRangedMinRange, 3.0, 20.0);
            case "ranged-optimal-range" -> setDouble(sender, value, s::setRangedOptimalRange, 10.0, 50.0);
            case "ranged-max-range" -> setDouble(sender, value, s::setRangedMaxRange, 15.0, 100.0);
            case "bow-draw-ticks" -> setInt(sender, value, s::setBowDrawTicks, 5, 100);
            case "arrow-prediction" -> setBool(sender, value, s::setArrowPrediction);
            case "ranged-strafe" -> setBool(sender, value, s::setRangedStrafe);
            case "ranged-retreat" -> setBool(sender, value, s::setRangedRetreat);
            default ->
                sender.sendMessage("§cUnknown setting: " + setting + ". Available: " + String.join(", ", SETTING_KEYS));
        }
    }

    private void setBool(CommandSender sender, String value, java.util.function.Consumer<Boolean> setter) {
        boolean v = parseBoolean(value);
        setter.accept(v);
        sender.sendMessage("§aSet to " + v);
    }

    private void setInt(CommandSender sender, String value, java.util.function.Consumer<Integer> setter, int min, int max) {
        try {
            int v = Integer.parseInt(value);
            setter.accept(v);
            sender.sendMessage("§aSet to " + v + " (clamped " + min + "-" + max + ")");
        } catch (NumberFormatException e) {
            sender.sendMessage("§cInvalid number: " + value);
        }
    }

    private void setDouble(CommandSender sender, String value, java.util.function.Consumer<Double> setter, double min, double max) {
        try {
            double v = Double.parseDouble(value);
            setter.accept(v);
            sender.sendMessage("§aSet to " + v + " (clamped " + min + "-" + max + ")");
        } catch (NumberFormatException e) {
            sender.sendMessage("§cInvalid number: " + value);
        }
    }

    private void handleMove(@NotNull CommandSender sender, @NotNull String[] args) {
        if (!(sender instanceof Player)) {
            sender.sendMessage("§cOnly players can use this command");
            return;
        }

        if (args.length < 5) {
            sender.sendMessage("§cUsage: /pvpbot move <botname> <x> <y> <z>");
            return;
        }

        String botName = args[1];
        CustomBot bot = botManager.getBot(botName);
        if (bot == null) {
            sender.sendMessage("§cNo bot found with name '" + botName + "'");
            return;
        }

        try {
            int x = Integer.parseInt(args[2]);
            int y = Integer.parseInt(args[3]);
            int z = Integer.parseInt(args[4]);
            bot.moveTo(new net.minecraft.core.BlockPos(x, y, z));
            sender.sendMessage("§aBot '" + botName + "' is moving to (" + x + ", " + y + ", " + z + ")");
        } catch (NumberFormatException e) {
            sender.sendMessage("§cInvalid coordinates");
        }
    }

    private void handleStop(@NotNull CommandSender sender, @NotNull String[] args) {
        if (args.length < 2) {
            sender.sendMessage("§cUsage: /pvpbot stop <botname>");
            return;
        }

        String botName = args[1];
        CustomBot bot = botManager.getBot(botName);
        if (bot == null) {
            sender.sendMessage("§cNo bot found with name '" + botName + "'");
            return;
        }

        bot.stopMovement();
        sender.sendMessage("§aBot '" + botName + "' stopped");
    }

    private boolean parseBoolean(@NotNull String value) {
        return value.equalsIgnoreCase("true") || value.equals("1") || value.equalsIgnoreCase("yes");
    }

    private void sendUsage(@NotNull CommandSender sender) {
        sender.sendMessage("§6=== PvPBot Commands ===");
        sender.sendMessage("§e/pvpbot spawn [name] §7- Spawn a bot at your location");
        sender.sendMessage("§e/pvpbot remove <name> §7- Remove a specific bot");
        sender.sendMessage("§e/pvpbot removeall §7- Remove all bots");
        sender.sendMessage("§e/pvpbot list §7- List active bots");
        sender.sendMessage("§e/pvpbot settings <bot> [<key> <val>] §7- View/change bot settings");
        sender.sendMessage("§e/pvpbot move <bot> <x> <y> <z> §7- Move a bot to a location");
        sender.sendMessage("§e/pvpbot stop <bot> §7- Stop a bot's movement");
        sender.sendMessage("§e/pvpbot reload §7- Reload configuration");
    }

    @Override
    public @Nullable List<String> onTabComplete(
            @NotNull CommandSender sender,
            @NotNull Command command,
            @NotNull String label,
            @NotNull String[] args
    ) {
        if (args.length == 1) {
            List<String> subs = new ArrayList<>(List.of("spawn", "remove", "list", "settings", "move", "stop"));
            if (sender.hasPermission("pvpbot.admin")) {
                subs.addAll(List.of("removeall", "reload"));
            }
            return subs.stream()
                    .filter(s -> s.startsWith(args[0].toLowerCase()))
                    .collect(Collectors.toList());
        }

        if (args.length == 2) {
            String cmd = args[0].toLowerCase();
            if (cmd.equals("remove") || cmd.equals("settings") || cmd.equals("move") || cmd.equals("stop")) {
                return botManager.getBotNames().stream()
                        .filter(name -> name.toLowerCase().startsWith(args[1].toLowerCase()))
                        .collect(Collectors.toList());
            }
        }

        if (args.length == 3 && args[0].equalsIgnoreCase("settings")) {
            return SETTING_KEYS.stream()
                    .filter(k -> k.startsWith(args[2].toLowerCase()))
                    .collect(Collectors.toList());
        }

        if (args.length == 4 && args[0].equalsIgnoreCase("settings")) {
            String key = args[2].toLowerCase();
            if (BOOLEAN_KEYS.contains(key)) {
                return Stream.of("true", "false")
                        .filter(v -> v.startsWith(args[3].toLowerCase()))
                        .collect(Collectors.toList());
            }
        }

        return Collections.emptyList();
    }
}

